INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020001-6001-4001-a001-bbbbbbbb0001','bb010001-5001-4001-9001-bbbbbbbb0001','tr','Modern Seralarımızda Güneş Enerjisi ile Sürdürülebilir Üretim','modern-seralarimizda-gunes-enerjisi-ile-surdurulebilir-uretim','{\"html\": \"<p>Bereket Fide olarak üretimde sürdürülebilirliği yalnızca bir hedef değil, günlük operasyonlarımızın doğal parçası olarak görüyoruz.</p><h2>Enerji Verimliliği Odaklı Sera Altyapısı</h2><p>Modern seralarımızda iklim kontrolü, sulama ve üretim süreçleri enerji verimliliğini destekleyecek şekilde planlanır. Bu yaklaşım hem üretim kalitesini korur hem de kaynak kullanımını dengeler.</p><h2>Güneş Enerjisi ile Desteklenen Üretim</h2><p>Tesislerimizde kullanılan yenilenebilir enerji yaklaşımı sayesinde çevresel etkileri azaltmayı ve daha istikrarlı bir üretim modeli oluşturmayı hedefliyoruz. Böylece yüksek kaliteli fide üretimini daha sorumlu bir altyapı ile sürdürüyoruz.</p><p>Çeşit ve sera planlaması için <strong>info@bereketfide.com.tr</strong> üzerinden teknik ekibimize ulaşabilirsiniz.</p>\"}','Güneş enerjisi ile çevreci fide üretimi.',NULL,'Sürdürülebilir Üretim | Bereket Fide Blog','Antalya Aksu tesislerimizde güneş enerjisi ve sürdürülebilir fide üretimi; teknik danışmanlık için iletişim.','sürdürülebilir üretim, güneş enerjisi, sera teknolojisi','2026-04-13 23:18:21.490','2026-04-13 23:18:21.490');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020002-6002-4002-a002-bbbbbbbb0002','bb010002-5002-4002-9002-bbbbbbbb0002','tr','2025 Sezonu Aşılı Fide Dikim Rehberi','2025-sezonu-asili-fide-dikim-rehberi','{\"html\": \"<p>Aşılı fide ile yüksek performanslı üretim hedefleyen yetiştiriciler için dikim öncesi planlama kritik önemdedir.</p><h2>Dikim Öncesi Hazırlık</h2><p>Toprak yapısının kontrol edilmesi, sulama planının hazırlanması ve sera ya da tarla koşullarının fideye uygun hale getirilmesi sezon başlangıcında büyük fark yaratır.</p><h2>Sağlıklı Başlangıç, Dengeli Gelişim</h2><p>Aşılı fidelerin güçlü kök yapısından en iyi şekilde yararlanmak için dikim sıklığı, ilk sulama ve adaptasyon dönemi dikkatle yönetilmelidir. Doğru başlangıç, sezon boyunca daha istikrarlı gelişim sağlar.</p><p>Bölgenize ve çeşide özel dikim takvimi için uzmanlarımızla görüşmekten çekinmeyin.</p>\"}','Aşılı fide dikim teknikleri.',NULL,'Aşılı Fide Dikim Rehberi 2025 | Bereket Fide Blog','2025 sezonu aşılı fide dikimi: hazırlık, sulama ve adaptasyon; Bereket Fide teknik destek.','aşılı fide, dikim rehberi, 2025 sezonu','2026-04-13 23:18:21.490','2026-04-13 23:18:21.490');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020003-6003-4003-a003-bbbbbbbb0003','bb010003-5003-4003-9003-bbbbbbbb0003','tr','Fide Kalitesini Artıran İnovatif Yaklaşımlar','fide-kalitesini-artiran-inovatif-yaklasimlar','{\"html\": \"<p>Kaliteli fide üretimi, yalnızca iyi tohum seçimiyle değil; süreç boyunca uygulanan yenilikçi yöntemlerle mümkün olur.</p><h2>Kontrollü Üretim Süreçleri</h2><p>Isı, nem, sulama ve besleme parametrelerinin kontrollü şekilde yönetilmesi, gelişim sürecinde daha homojen ve güçlü fideler elde edilmesini sağlar.</p><h2>Veri ve Gözleme Dayalı İyileştirme</h2><p>Üretim sahasında yapılan düzenli gözlemler ve performans takibi, kaliteyi artıran kararların daha hızlı alınmasına yardımcı olur. Bu yaklaşım, sezon boyunca daha güçlü ve güvenilir sonuçlar üretir.</p><p>Toptan alım ve çeşit güvencesi hakkında teklif formumuzdan bize yazabilirsiniz.</p>\"}','Kaliteli fide üretimi için inovasyon.',NULL,'İnovatif Fide Üretimi | Bereket Fide Blog','Kontrollü sera süreçleri ve kaliteli fide; Bereket Fide üretim yaklaşımı.','fide kalitesi, inovasyon, üretim teknolojisi','2026-04-13 23:18:21.490','2026-04-13 23:18:21.490');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020004-6004-4004-a004-bbbbbbbb0004','bb010004-5004-4004-9004-bbbbbbbb0004','tr','Fide Dikim Öncesi Toprak Hazırlığı','fide-dikim-oncesi-toprak-hazirligi','{\"html\": \"<p>Tarlanın fide dikimine hazırlanması, köklerin tutunma başarısını doğrudan etkiler. Adım adım hazırlık süreci.</p><h2>Toprak Analizi</h2><p>Dikim öncesi mutlaka toprak analizi yaptırılmalı ve ihtiyaç duyulan elementler belirlenmelidir.</p><h2>Gübreleme ve İşleme</h2><p>Toprağın havalandırılması ve organik madde miktarının artırılması, fidenin yeni yerine adaptasyonunu hızlandırır.</p><p>pH, tuzluluk ve drenaj konularında yerel koşullara göre öneri almak, ilk haftalardaki stresi azaltır.</p>\"}','Toprak analizi, gübreleme ve havalandırma ile dikim öncesi hazırlık.',NULL,'Toprak Hazırlığı Rehberi | Bereket Fide Bilgi Bankası','Fide dikim öncesi toprak analizi, gübreleme ve işleme; adaptasyon ipuçları.','toprak hazırlığı, fide dikimi, gübreleme','2026-04-13 23:18:21.490','2026-04-13 23:18:21.490');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020005-6005-4005-a005-bbbbbbbb0005','bb010001-5001-4001-9001-bbbbbbbb0001','en','Sustainable Production with Solar Energy in Our Modern Greenhouses','sustainable-production-with-solar-energy-in-our-modern-greenhouses','{\"html\": \"<p>At Bereket Fide, we treat sustainability as a practical part of daily production rather than a separate initiative.</p><h2>Energy-Efficient Greenhouse Infrastructure</h2><p>Climate control, irrigation and production systems in our modern greenhouses are planned to support efficient resource use while maintaining stable product quality.</p><h2>Renewable Energy Supported Production</h2><p>By integrating a renewable energy approach into our facilities, we aim to reduce environmental impact and build a more resilient production model for high quality seedlings.</p><p>For variety and greenhouse planning, contact our technical team at <strong>info@bereketfide.com.tr</strong>.</p>\"}','Eco-friendly seedling production with solar energy.',NULL,'Sustainable Production | Bereket Fide Blog','Solar-backed sustainable seedling production in Antalya; technical advice via Bereket Fide.','sustainable production, solar energy, greenhouse systems','2026-04-13 23:18:21.491','2026-04-13 23:18:21.491');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020006-6006-4006-a006-bbbbbbbb0006','bb010002-5002-4002-9002-bbbbbbbb0002','en','2025 Season Grafted Seedling Planting Guide','2025-season-grafted-seedling-planting-guide','{\"html\": \"<p>For growers targeting high performance production with grafted seedlings, planning before planting is essential.</p><h2>Preparation Before Planting</h2><p>Checking soil structure, preparing irrigation planning and aligning greenhouse or field conditions with the crop helps the season start in a stronger way.</p><h2>Healthy Start, Balanced Development</h2><p>To benefit from the strong root structure of grafted seedlings, planting density, first irrigation and the adaptation period should be managed carefully from day one.</p><p>Ask our agronomy team for a planting calendar suited to your region and variety mix.</p>\"}','Grafted seedling planting techniques.',NULL,'2025 Grafted Seedling Planting Guide | Bereket Fide Blog','Grafted seedling planting in 2025: soil, irrigation, adaptation; Bereket Fide support.','grafted seedlings, planting guide, 2025 season','2026-04-13 23:18:21.491','2026-04-13 23:18:21.491');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020007-6007-4007-a007-bbbbbbbb0007','bb010003-5003-4003-9003-bbbbbbbb0003','en','Innovative Approaches That Improve Seedling Quality','innovative-approaches-that-improve-seedling-quality','{\"html\": \"<p>High quality seedling production depends not only on seed selection but also on the innovative practices applied throughout the production cycle.</p><h2>Controlled Production Processes</h2><p>Managing temperature, humidity, irrigation and nutrition in a controlled way helps deliver more uniform and stronger seedlings.</p><h2>Observation and Data Driven Improvement</h2><p>Regular monitoring in the production area makes it easier to take timely quality decisions and maintain reliable results across the season.</p><p>Use our quote form for bulk orders and variety availability.</p>\"}','Innovation for quality seedling production.',NULL,'Innovative Seedling Production | Bereket Fide Blog','Controlled greenhouse processes for consistent seedling quality at Bereket Fide.','seedling quality, innovation, production methods','2026-04-13 23:18:21.491','2026-04-13 23:18:21.491');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020008-6008-4008-a008-bbbbbbbb0008','bb010004-5004-4004-9004-bbbbbbbb0004','en','Soil Preparation Before Seedling Planting','soil-preparation-before-planting','{\"html\": \"<p>Preparing the field for seedling planting directly affects the success of the roots. Step-by-step preparation process.</p><h2>Soil Analysis</h2><p>Soil analysis should definitely be performed before planting and the required elements should be determined.</p><h2>Fertilization and Processing</h2><p>Aerating the soil and increasing the amount of organic matter accelerates the adaptation of the seedling to its new place.</p><p>Review pH, salinity and drainage with local conditions in mind to reduce early-season stress.</p>\"}','Soil analysis, fertilization, and aeration before planting.',NULL,'Soil Preparation Guide | Bereket Fide Knowledge Base','Pre-plant soil analysis, fertilization and tillage for better seedling establishment.','soil preparation, seedling planting, fertilization','2026-04-13 23:18:21.491','2026-04-13 23:18:21.491');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020009-6009-4009-a009-bbbbbbbb0009','bb010001-5001-4001-9001-bbbbbbbb0001','de','Nachhaltige Produktion mit Solarenergie in unseren modernen Gewächshäusern','nachhaltige-produktion-solarenergie-gewaechshaeuser','{\"html\": \"<p>Bei Bereket Fide ist Nachhaltigkeit kein separates Projekt, sondern Teil des täglichen Produktionsalltags.</p><h2>Energieeffiziente Gewächshausinfrastruktur</h2><p>Klima, Bewässerung und Abläufe in unseren modernen Gewächshäusern sind so geplant, dass Ressourcen effizient genutzt und gleichzeitig eine stabile Produktqualität erhalten bleibt.</p><h2>Erneuerbare Energie in der Produktion</h2><p>Durch den Einsatz erneuerbarer Energie in unseren Anlagen wollen wir die Umweltbelastung verringern und ein widerstandsfähigeres Modell für hochwertige Jungpflanzen aufbauen.</p><p>Für Sorten- und Gewächshausplanung erreichen Sie unser Technikteam unter <strong>info@bereketfide.com.tr</strong>.</p>\"}','Umweltfreundliche Jungpflanzenproduktion mit Solarenergie.',NULL,'Nachhaltige Produktion | Bereket Fide Blog','Nachhaltige Jungpflanzenproduktion mit Solarenergie in Antalya; Beratung bei Bereket Fide.','nachhaltige Produktion, Solarenergie, Gewächshaus','2026-04-13 23:18:21.492','2026-04-13 23:18:21.492');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020010-6010-4010-a010-bbbbbbbb0010','bb010002-5002-4002-9002-bbbbbbbb0002','de','Pflanzleitfaden für veredelte Jungpflanzen — Saison 2025','pflanzleitfaden-veredelte-jungpflanzen-2025','{\"html\": \"<p>Für Betriebe mit hohen Erwartungen an veredelte Jungpflanzen ist die Planung vor der Pflanzung entscheidend.</p><h2>Vorbereitung vor der Pflanzung</h2><p>Bodenstruktur prüfen, Bewässerung planen und Feld- oder Gewächshausbedingungen an die Kultur anpassen — so startet die Saison robuster.</p><h2>Gesunder Start, ausgewogene Entwicklung</h2><p>Um die starke Wurzelstruktur veredelter Jungpflanzen optimal zu nutzen, sollten Pflanzdichte, erste Bewässerung und die Eingewöhnungsphase von Anfang an sorgfältig geführt werden.</p><p>Unser Agrarteam erstellt gern einen Pflanzkalender passend zu Region und Sortiment.</p>\"}','Techniken für die Pflanzung veredelter Jungpflanzen.',NULL,'Pflanzleitfaden 2025 | Bereket Fide Blog','Veredelte Jungpflanzen 2025: Vorbereitung, Bewässerung, Eingewöhnung; Bereket Fide.','veredelte Jungpflanzen, Pflanzleitfaden, Saison 2025','2026-04-13 23:18:21.492','2026-04-13 23:18:21.492');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020011-6011-4011-a011-bbbbbbbb0011','bb010003-5003-4003-9003-bbbbbbbb0003','de','Innovative Ansätze zur Verbesserung der Jungpflanzenqualität','innovative-ansaetze-jungpflanzenqualitaet','{\"html\": \"<p>Hochwertige Jungpflanzen entstehen nicht nur durch die Saatgutwahl, sondern durch durchgängige, innovative Praxis im Produktionszyklus.</p><h2>Kontrollierte Produktionsprozesse</h2><p>Die gezielte Steuerung von Temperatur, Luftfeuchte, Bewässerung und Ernährung führt zu gleichmäßigeren und kräftigeren Jungpflanzen.</p><h2>Verbesserung durch Beobachtung und Daten</h2><p>Regelmäßige Kontrolle im Produktionsbereich erleichtert rechtzeitige Qualitätsentscheidungen und zuverlässige Ergebnisse über die Saison.</p><p>Für Mengenbestellungen und Sortenverfügbarkeit nutzen Sie unser Angebotsformular.</p>\"}','Innovation für qualitativ hochwertige Jungpflanzen.',NULL,'Innovative Jungpflanzenproduktion | Bereket Fide Blog','Kontrollierte Gewächshausprozesse für gleichbleibende Jungpflanzenqualität.','Jungpflanzenqualität, Innovation, Produktion','2026-04-13 23:18:21.492','2026-04-13 23:18:21.492');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bb020012-6012-4012-a012-bbbbbbbb0012','bb010004-5004-4004-9004-bbbbbbbb0004','de','Bodenvorbereitung vor der Jungpflanzenkultur','bodenvorbereitung-vor-jungpflanzenkultur','{\"html\": \"<p>Die Vorbereitung des Feldes vor der Jungpflanzenkultur beeinflusst direkt das Anwachsen der Wurzeln. Schritt für Schritt.</p><h2>Bodenanalyse</h2><p>Vor der Pflanzung sollte eine Bodenanalyse erfolgen; fehlende Nährstoffe werden so gezielt ergänzt.</p><h2>Düngung und Bearbeitung</h2><p>Lockern des Bodens und mehr organischer Substanz beschleunigen die Eingewöhnung der Jungpflanze am neuen Standort.</p><p>pH, Salzgehalt und Drainage sollten standortspezifisch geprüft werden, um Stress in den ersten Wochen zu reduzieren.</p>\"}','Bodenanalyse, Düngung und Lockerung für erfolgreichere Pflanzung.',NULL,'Bodenvorbereitung | Bereket Fide Wissensbasis','Vor der Jungpflanzenkultur: Analyse, Düngung, Bearbeitung; Eingewöhnung.','Bodenvorbereitung, Jungpflanzen, Düngung','2026-04-13 23:18:21.492','2026-04-13 23:18:21.492');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020001-6001-4001-a001-cccccccc0001','bc010001-5001-4001-9001-cccccccc0001','tr','Hakkımızda','about','{\"html\": \"<p><strong>Kaliteli ve yüksek verimli fide üretimi</strong> için modern seralarımızda aşılı ve standart fide üretimi yapıyoruz; sürdürülebilir üretimde tesis enerjimizi güneş panellerimizle karşılıyoruz.</p><h2>Bereket Fide Hakkında</h2><p>Bereket Fide, 2006 yılında Antalya ili Aksu ilçesi Çamköy’de bölgedeki hazır fide ihtiyacını karşılamak amacıyla kurulmuştur. Bugün itibarıyla 32.000 m² toplam arazi üzerinde, 24.000 m² modern ve bilgisayar kontrollü seralarda üretim yapmaktadır.</p><p>Yıllık 16-17 milyon aşılı fide ve 18-20 milyon normal fide üretim kapasitesine sahip olan tesisimiz, bölgenin en modern üretim merkezlerinden biridir.</p><h2>Teknoloji ve Üretim</h2><p>Üretim süreçlerimizin tamamı bilgisayar kontrollü sulama, gübreleme, ısıtma ve nemlendirme sistemleri ile yönetilmektedir. Ayrıca, çevreye duyarlı üretim anlayışımızla tüm tesisimizin enerji ihtiyacı kendi güneş panellerimizden (yenilenebilir enerji) karşılanmaktadır.</p><h2>Kalite Politikamız</h2><p>Sürekli değişen müşteri taleplerini, teknoloji ve inovasyon odaklı satış stratejisi ile takip ederek müşteri memnuniyetini en üst düzeyde tutmayı hedefliyoruz. Tedarikçilerimiz ve çalışanlarımızla iş birliği içerisinde, sosyal sorumluluk ve çevre bilinci yüksek bir marka olma yolunda gelişmeye devam ediyoruz.</p>\"}','Kaliteli ve yüksek verimli fide: modern seralarda aşılı ve standart üretim; Antalya Aksu’da 24.000 m² bilgisayar kontrollü tesis ve yenilenebilir enerji.',NULL,'Hakkımızda | Bereket Fide','Bereket Fide: kaliteli fide üretimi, modern seralar ve sürdürülebilir enerji. Antalya Aksu’da 2006’dan beri aşılı ve normal fide.','bereket fide, hakkımızda, fide üretimi, antalya fide, aşılı fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020002-6002-4002-a002-cccccccc0002','bc010002-5002-4002-9002-cccccccc0002','tr','Gizlilik Politikası','privacy','{\"html\": \"<h2>Gizlilik Politikası</h2><p>Bereket Fide Tarım San. ve Tic. Ltd. Şti. (\\\"Bereket Fide\\\") olarak, <strong>www.bereketfide.com.tr</strong> web sitesi üzerinden toplanan kişisel verilerin gizliliğini ve güvenliğini en üst düzeyde korumayı taahhüt ediyoruz. Bu Gizlilik Politikası, hangi verilerin toplandığını, nasıl kullanıldığını ve korunduğunu açıklamaktadır.</p><h3>1. Toplanan Veriler</h3><p>Web sitemizi ziyaret ettiğinizde ve formlarımızı doldurduğunuzda aşağıdaki veriler toplanabilir:</p><ul><li><strong>Kimlik bilgileri:</strong> Ad, soyad, firma adı</li><li><strong>İletişim bilgileri:</strong> E-posta adresi, telefon numarası, adres</li><li><strong>Talep bilgileri:</strong> Teklif formu üzerinden ilettiğiniz ürün tercihleri, miktar ve teslimat bilgileri</li><li><strong>Teknik veriler:</strong> IP adresi, tarayıcı türü, ziyaret edilen sayfalar, çerez verileri</li></ul><h3>2. Verilerin Kullanım Amacı</h3><p>Toplanan kişisel veriler aşağıdaki amaçlarla kullanılmaktadır:</p><ul><li>Müşteri teklif taleplerinin değerlendirilmesi ve yanıtlanması</li><li>Sipariş süreçlerinin yönetimi ve lojistik planlaması</li><li>Ürün ve hizmetlerimiz hakkında bilgilendirme yapılması</li><li>Web sitesi deneyiminin iyileştirilmesi ve analiz edilmesi</li><li>Yasal yükümlülüklerin yerine getirilmesi</li></ul><h3>3. Verilerin Paylaşımı</h3><p>Kişisel verileriniz, açık rızanız olmaksızın üçüncü kişilerle paylaşılmaz. Ancak yasal zorunluluklar, resmi kurum talepleri veya hizmet sağlayıcılarımızla (hosting, e-posta, lojistik) sınırlı kapsamda paylaşılabilir.</p><h3>4. Veri Güvenliği</h3><p>Verileriniz SSL şifreleme, güvenlik duvarları ve düzenli güvenlik güncellemeleri ile korunmaktadır. Yetkisiz erişime karşı teknik ve idari tedbirler alınmaktadır.</p><h3>5. Çerezler</h3><p>Web sitemizde kullanıcı deneyimini iyileştirmek amacıyla çerezler kullanılmaktadır. Çerezler hakkında detaylı bilgi için Çerez Politikamızı inceleyebilirsiniz.</p><h3>6. Haklarınız</h3><p>6698 sayılı Kişisel Verilerin Korunması Kanunu (KVKK) kapsamında aşağıdaki haklara sahipsiniz:</p><ul><li>Kişisel verilerinizin işlenip işlenmediğini öğrenme</li><li>Verilerin düzeltilmesini veya silinmesini talep etme</li><li>İşlemenin kısıtlanmasını isteme</li><li>Veri taşınabilirliği hakkı</li><li>İtiraz hakkı</li></ul><h3>7. İletişim</h3><p>Gizlilik politikamız hakkında sorularınız için <strong>info@bereketfide.com.tr</strong> adresinden bizimle iletişime geçebilirsiniz.</p><p><em>Son güncelleme: Mart 2026</em></p>\"}','Bereket Fide gizlilik politikası — kişisel verilerin toplanması, kullanımı ve korunması hakkında detaylı bilgilendirme.',NULL,'Gizlilik Politikası | Bereket Fide','Bereket Fide gizlilik politikası ve kişisel veri işleme esasları. KVKK kapsamında haklarınız.','gizlilik politikası, kvkk, kişisel veri, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020003-6003-4003-a003-cccccccc0003','bc010003-5003-4003-9003-cccccccc0003','tr','Kullanım Koşulları','terms','{\"html\": \"<h2>Kullanım Koşulları</h2><p><strong>www.bereketfide.com.tr</strong> web sitesini (\\\"Site\\\") kullanarak aşağıdaki kullanım koşullarını kabul etmiş sayılırsınız. Lütfen bu koşulları dikkatlice okuyunuz.</p><h3>1. Genel Hükümler</h3><p>Bu Site, Bereket Fide Tarım San. ve Tic. Ltd. Şti. (\\\"Bereket Fide\\\") tarafından işletilmektedir. Sitedeki tüm içerikler (metin, görsel, logo, grafik, video) Bereket Fide\'nin mülkiyetinde olup, telif hakları yasaları ile korunmaktadır.</p><h3>2. Fikri Mülkiyet</h3><p>Sitede yer alan tüm içerikler, tasarımlar, logolar, görseller ve yazılımlar Bereket Fide\'ye aittir. Bu içeriklerin izinsiz kopyalanması, çoğaltılması, dağıtılması veya değiştirilmesi yasaktır ve yasal işlem başlatılabilir.</p><h3>3. Ürün ve Hizmet Bilgileri</h3><p>Sitedeki ürün açıklamaları, fiyatlar ve teknik bilgiler bilgilendirme amaçlıdır. Bereket Fide, bu bilgilerde önceden haber vermeksizin değişiklik yapma hakkını saklı tutar. Kesin fiyat ve stok bilgisi için doğrudan iletişime geçmeniz önerilir.</p><h3>4. Teklif ve Sipariş</h3><p>Site üzerinden gönderilen teklif talepleri bağlayıcı sipariş niteliği taşımaz. Her teklif, Bereket Fide tarafından değerlendirildikten sonra müşteriye ayrıca iletilir. Sipariş ancak karşılıklı yazılı onay ile kesinleşir.</p><h3>5. Sorumluluk Sınırlaması</h3><ul><li>Bereket Fide, sitedeki bilgilerin doğruluğu konusunda azami özen gösterir ancak hata olasılığını tamamen ortadan kaldıramaz.</li><li>Site üzerindeki dış bağlantıların (linkler) içeriklerinden Bereket Fide sorumlu değildir.</li><li>Teknik arızalar, bakım çalışmaları veya mücbir sebepler nedeniyle sitenin geçici olarak erişilemez olmasından dolayı sorumluluk kabul edilmez.</li></ul><h3>6. Gizlilik</h3><p>Kişisel verilerinizin işlenmesi hakkında detaylı bilgi için <a href=\\\"/tr/legal/privacy\\\">Gizlilik Politikamızı</a> inceleyebilirsiniz.</p><h3>7. Uygulanacak Hukuk</h3><p>Bu kullanım koşulları Türkiye Cumhuriyeti kanunlarına tabidir. Uyuşmazlıklarda Antalya Mahkemeleri ve İcra Daireleri yetkilidir.</p><h3>8. Değişiklikler</h3><p>Bereket Fide, bu kullanım koşullarını herhangi bir zamanda güncelleme hakkını saklı tutar. Güncel versiyon her zaman bu sayfada yayınlanır.</p><h3>9. İletişim</h3><p>Kullanım koşulları hakkında sorularınız için <strong>info@bereketfide.com.tr</strong> adresinden bizimle iletişime geçebilirsiniz.</p><p><em>Son güncelleme: Mart 2026</em></p>\"}','Bereket Fide web sitesi kullanım koşulları — fikri mülkiyet, sorumluluk sınırlaması ve yasal hükümler.',NULL,'Kullanım Koşulları | Bereket Fide','Bereket Fide web sitesi kullanım koşulları, fikri mülkiyet hakları ve yasal bilgilendirme.','kullanım koşulları, yasal, fikri mülkiyet, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020004-6004-4004-a004-cccccccc0004','bc010004-5004-4004-9004-cccccccc0004','tr','KVKK Aydınlatma Metni','kvkk-aydinlatma-metni','{\"html\": \"<h2>KVKK Aydınlatma Metni</h2><p>6698 sayılı Kişisel Verilerin Korunması Kanunu (KVKK) kapsamında, veri sorumlusu Bereket Fide Tarım San. ve Tic. Ltd. Şti. olarak kişisel verilerinizin işlenmesi hakkında sizi bilgilendiriyoruz.</p><h3>İşlenen veriler ve amaçlar</h3><p>İletişim formları, teklif talepleri ve sipariş süreçleri kapsamında kimlik, iletişim ve talebe ilişkin veriler; talebin karşılanması, sözleşmenin ifası, müşteri ilişkilerinin yürütülmesi ve yasal yükümlülüklerin yerine getirilmesi amacıyla işlenir.</p><h3>Hukuki sebep ve aktarım</h3><p>Verileriniz KVKK md. 5/2 kapsamında sözleşmenin kurulması veya ifası, hukuki yükümlülük ve meşru menfaat gereklilikleri çerçevesinde işlenebilir; yasal zorunluluk ve hizmet sağlayıcılarla sınırlı paylaşım yapılabilir.</p><h3>Haklarınız</h3><p>KVKK md. 11 kapsamında verilerinizin işlenip işlenmediğini öğrenme, düzeltilmesini veya silinmesini talep etme, işlemenin kısıtlanmasını isteme, veri taşınabilirliği ve itiraz haklarına sahipsiniz.</p><h3>Başvuru</h3><p>Taleplerinizi <strong>info@bereketfide.com.tr</strong> adresine iletebilirsiniz.</p><p><em>Son güncelleme: Nisan 2026</em></p>\"}','Bereket Fide KVKK aydınlatma metni — işleme amaçları ve haklar.',NULL,'KVKK Aydınlatma Metni | Bereket Fide','Bereket Fide kişisel verilerin korunması kanunu bilgilendirmesi.','kvkk, aydınlatma metni, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020005-6005-4005-a005-cccccccc0005','bc010005-5005-4005-9005-cccccccc0005','tr','Çerez Politikası','cookies','{\"html\": \"<h2>Çerez Politikası</h2><p>Bu politika, <strong>www.bereketfide.com.tr</strong> sitesinde çerezlerin nasıl kullanıldığını açıklar.</p><h3>Çerez nedir?</h3><p>Çerezler, tarayıcınızda saklanan küçük metin dosyalarıdır; site performansını ölçmek, tercihlerinizi hatırlamak ve güvenliği desteklemek için kullanılabilir.</p><h3>Kullandığımız çerez türleri</h3><ul><li><strong>Zorunlu:</strong> sitenin temel işlevleri için gerekli</li><li><strong>Tercih / işlevsel:</strong> dil veya form tercihleri gibi</li><li><strong>İstatistik (varsa):</strong> anonim veya toplu kullanım analizi</li></ul><h3>Yönetim</h3><p>Tarayıcı ayarlarından çerezleri silebilir veya engelleyebilirsiniz; bazı özellikler kısıtlanabilir.</p><h3>İletişim</h3><p>Sorularınız için <strong>info@bereketfide.com.tr</strong></p><p><em>Son güncelleme: Nisan 2026</em></p>\"}','Bereket Fide çerez kullanımı ve yönetim bilgisi.',NULL,'Çerez Politikası | Bereket Fide','Bereket Fide çerez politikası ve kullanımı.','çerezler, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020006-6006-4006-a006-cccccccc0006','bc010001-5001-4001-9001-cccccccc0001','en','About Us','about','{\"html\": \"<p>We focus on <strong>high-quality, high-yield seedling production</strong>, growing grafted and standard seedlings in modern greenhouses, with renewable energy from our solar panels.</p><h2>About Bereket Fide</h2><p>Bereket Fide was established in 2006 in Aksu, Antalya, to meet the growing demand for ready-made seedlings. Today, it operates on a total area of 32,000 m², with 24,000 m² of modern and computer-controlled greenhouses.</p><p>With an annual production capacity of 16-17 million grafted seedlings and 18-20 million normal seedlings, our facility is one of the most modern production centers in the region.</p><h2>Technology and Production</h2><p>All of our production processes are managed by computer-controlled irrigation, fertilization, heating, and humidification systems. Furthermore, with our environment-friendly production approach, the energy needs of our entire facility are met by our own solar panels (renewable energy).</p><h2>Our Quality Policy</h2><p>We aim to keep customer satisfaction at the highest level by following constantly changing customer demands with a technology and innovation-oriented sales strategy. In cooperation with our suppliers and employees, we continue to develop as a brand with high social responsibility and environmental awareness.</p>\"}','Quality seedlings in modern greenhouses: grafted and standard production; 24,000 m² computer-controlled facility in Antalya Aksu with renewable energy.',NULL,'About Us | Bereket Fide','Bereket Fide: quality seedling production, modern greenhouses and solar-powered operations in Antalya Aksu since 2006.','bereket fide, about us, seedling production, grafted seedlings','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020007-6007-4007-a007-cccccccc0007','bc010002-5002-4002-9002-cccccccc0002','en','Privacy Policy','privacy','{\"html\": \"<h2>Privacy Policy</h2><p>Bereket Fide Tarım San. ve Tic. Ltd. Şti. (\\\"Bereket Fide\\\") is committed to protecting the privacy and security of personal data collected through <strong>www.bereketfide.com.tr</strong>. This Privacy Policy explains what data is collected, how it is used, and how it is protected.</p><h3>1. Data Collected</h3><p>When you visit our website and fill in our forms, the following data may be collected:</p><ul><li><strong>Identity information:</strong> Name, surname, company name</li><li><strong>Contact information:</strong> Email address, phone number, address</li><li><strong>Request information:</strong> Product preferences, quantity, and delivery details submitted via the quote form</li><li><strong>Technical data:</strong> IP address, browser type, pages visited, cookie data</li></ul><h3>2. Purpose of Data Use</h3><p>Collected personal data is used for the following purposes:</p><ul><li>Evaluating and responding to customer quote requests</li><li>Managing order processes and logistics planning</li><li>Providing information about our products and services</li><li>Improving and analyzing website experience</li><li>Fulfilling legal obligations</li></ul><h3>3. Data Sharing</h3><p>Your personal data will not be shared with third parties without your explicit consent. However, it may be shared in limited scope with legal requirements, official authorities, or our service providers (hosting, email, logistics).</p><h3>4. Data Security</h3><p>Your data is protected with SSL encryption, firewalls, and regular security updates. Technical and administrative measures are taken against unauthorized access.</p><h3>5. Your Rights</h3><p>Under the Personal Data Protection Law (KVKK No. 6698), you have the right to:</p><ul><li>Learn whether your personal data is being processed</li><li>Request correction or deletion of your data</li><li>Request restriction of processing</li><li>Data portability</li><li>Object to processing</li></ul><h3>6. Contact</h3><p>For questions about our privacy policy, please contact us at <strong>info@bereketfide.com.tr</strong>.</p><p><em>Last updated: March 2026</em></p>\"}','Bereket Fide privacy policy — detailed information about collection, use and protection of personal data.',NULL,'Privacy Policy | Bereket Fide','Bereket Fide privacy policy and personal data processing principles.','privacy policy, personal data, gdpr, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020008-6008-4008-a008-cccccccc0008','bc010003-5003-4003-9003-cccccccc0003','en','Terms of Use','terms','{\"html\": \"<h2>Terms of Use</h2><p>By using the <strong>www.bereketfide.com.tr</strong> website (\\\"Site\\\"), you agree to the following terms and conditions. Please read these terms carefully.</p><h3>1. General Provisions</h3><p>This Site is operated by Bereket Fide Tarım San. ve Tic. Ltd. Şti. (\\\"Bereket Fide\\\"). All content on the Site (text, images, logos, graphics, video) is the property of Bereket Fide and is protected by copyright laws.</p><h3>2. Intellectual Property</h3><p>All content, designs, logos, visuals, and software on the Site belong to Bereket Fide. Unauthorized copying, reproduction, distribution, or modification of this content is prohibited and may result in legal action.</p><h3>3. Product and Service Information</h3><p>Product descriptions, prices, and technical information on the Site are for informational purposes. Bereket Fide reserves the right to make changes without prior notice. For exact pricing and stock information, please contact us directly.</p><h3>4. Quotes and Orders</h3><p>Quote requests submitted through the Site do not constitute binding orders. Each quote is evaluated by Bereket Fide and separately communicated to the customer. Orders are finalized only with mutual written confirmation.</p><h3>5. Limitation of Liability</h3><ul><li>Bereket Fide takes maximum care regarding the accuracy of information on the Site but cannot completely eliminate the possibility of errors.</li><li>Bereket Fide is not responsible for the content of external links on the Site.</li><li>No liability is accepted for temporary inaccessibility of the Site due to technical failures, maintenance, or force majeure.</li></ul><h3>6. Governing Law</h3><p>These terms of use are governed by the laws of the Republic of Turkey. Antalya Courts and Enforcement Offices have jurisdiction in disputes.</p><h3>7. Contact</h3><p>For questions about these terms, please contact us at <strong>info@bereketfide.com.tr</strong>.</p><p><em>Last updated: March 2026</em></p>\"}','Bereket Fide website terms of use — intellectual property, liability limitations and legal provisions.',NULL,'Terms of Use | Bereket Fide','Bereket Fide website terms of use, intellectual property rights and legal information.','terms of use, legal, intellectual property, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020009-6009-4009-a009-cccccccc0009','bc010004-5004-4004-9004-cccccccc0004','en','PDPL Information Notice','pdpl-information-notice','{\"html\": \"<h2>Personal Data Protection Law Notice</h2><p>Under Law No. 6698 on the Protection of Personal Data (PDPL / KVKK), Bereket Fide Tarım San. ve Tic. Ltd. Şti. informs you about the processing of your personal data.</p><h3>Data and purposes</h3><p>Identity, contact and request-related data collected through contact forms, quote requests and order processes may be processed to respond to requests, perform contracts, manage customer relations and comply with legal obligations.</p><h3>Legal basis and transfers</h3><p>Processing may rely on contract performance, legal obligation and legitimate interests under PDPL; limited sharing may occur with service providers or authorities where required by law.</p><h3>Your rights</h3><p>You may request information, correction, deletion, restriction of processing, data portability and object to processing in line with PDPL Article 11.</p><h3>Contact</h3><p>Please contact <strong>info@bereketfide.com.tr</strong> for requests.</p><p><em>Last updated: April 2026</em></p>\"}','Bereket Fide PDPL notice — processing purposes and your rights.',NULL,'PDPL Information Notice | Bereket Fide','Bereket Fide personal data protection law notice.','pdpl, kvkk, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020010-6010-4010-a010-cccccccc0010','bc010005-5005-4005-9005-cccccccc0005','en','Cookie Policy','cookies','{\"html\": \"<h2>Cookie Policy</h2><p>This policy explains how cookies are used on <strong>www.bereketfide.com.tr</strong>.</p><h3>What are cookies?</h3><p>Cookies are small text files stored in your browser. They may be used to measure site performance, remember preferences and support security.</p><h3>Types we may use</h3><ul><li><strong>Strictly necessary:</strong> required for core site functionality</li><li><strong>Functional / preference:</strong> e.g. language or form state</li><li><strong>Analytics (if enabled):</strong> aggregated or anonymised usage insights</li></ul><h3>Managing cookies</h3><p>You can delete or block cookies in your browser settings; some features may be limited.</p><h3>Contact</h3><p><strong>info@bereketfide.com.tr</strong></p><p><em>Last updated: April 2026</em></p>\"}','Bereket Fide cookie usage and how to manage preferences.',NULL,'Cookie Policy | Bereket Fide','Bereket Fide cookie usage and policy.','cookies, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020011-6011-4011-a011-cccccccc0011','bc010006-5006-4006-9006-cccccccc0006','tr','Kalite Politikamız','kalite-politikasi','{\"html\": \"<h2>Kalite Politikamız</h2><p>Bereket Fide olarak sebze fidesi üretiminde müşteri beklentilerini, yasal mevzuatı ve sürdürülebilir tarım ilkelerini esas alıyoruz.</p><h3>Hedeflerimiz</h3><ul><li>Sağlıklı fide, tutarlı çeşit performansı ve zamanında teslimat</li><li>Üretim süreçlerinde izlenebilirlik ve kayıt tutma</li><li>Çalışan eğitimi ve sürekli iyileştirme</li><li>Çevreye duyarlı üretim (örnekleme, girdi yönetimi, atık minimizasyonu)</li></ul><h3>Uygulama</h3><p>Kalite anlayışımız; tohumdan fideye kadar üretim adımlarında kontrol noktaları, hijyen ve teknik standartlarla desteklenir. İyileştirme önerileri müşteri geri bildirimi ve iç denetimlerle değerlendirilir.</p><p><em>Son güncelleme: Nisan 2026</em></p>\"}','Bereket Fide kalite politikası: sağlıklı fide, izlenebilir üretim ve müşteri memnuniyeti.',NULL,'Kalite Politikası | Bereket Fide','Bereket Fide kalite politikası ve üretim taahhütleri.','kalite politikası, fide üretimi, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020012-6012-4012-a012-cccccccc0012','bc010006-5006-4006-9006-cccccccc0006','en','Quality Policy','quality-policy','{\"html\": \"<h2>Quality Policy</h2><p>At Bereket Fide we align vegetable seedling production with customer expectations, applicable regulations, and sustainable agriculture principles.</p><h3>Objectives</h3><ul><li>Healthy seedlings, consistent variety performance, and on-time delivery</li><li>Traceability and record-keeping across production steps</li><li>Staff training and continuous improvement</li><li>Environmentally responsible production (inputs, sampling, waste minimization)</li></ul><h3>Implementation</h3><p>Our approach is supported by control points from seed to seedling, hygiene, and technical standards. Improvements are reviewed through customer feedback and internal checks.</p><p><em>Last updated: April 2026</em></p>\"}','Bereket Fide quality policy: healthy seedlings, traceable production, customer focus.',NULL,'Quality Policy | Bereket Fide','Bereket Fide quality policy and production commitments.','quality policy, seedling production, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020013-6013-4013-a013-cccccccc0013','bc010006-5006-4006-9006-cccccccc0006','de','Qualitätspolitik','qualitaetspolitik','{\"html\": \"<h2>Qualitätspolitik</h2><p>Bei Bereket Fide richten wir die Produktion von Gemüsepflanzen an Kundenerwartungen, geltenden Vorschriften und Grundsätzen nachhaltiger Landwirtschaft aus.</p><h3>Ziele</h3><ul><li>Gesunde Pflanzen, gleichbleibende Sortenleistung und termingerechte Lieferung</li><li>Rückverfolgbarkeit und Dokumentation in der Produktion</li><li>Schulung der Mitarbeitenden und kontinuierliche Verbesserung</li><li>Umweltbewusste Produktion (Einsatzstoffe, Probenahme, Abfallminimierung)</li></ul><h3>Umsetzung</h3><p>Unser Ansatz stützt sich auf Kontrollpunkte vom Saatgut bis zur Pflanze, Hygiene und technische Standards. Verbesserungen werden über Kundenfeedback und interne Prüfungen bewertet.</p><p><em>Stand: April 2026</em></p>\"}','Qualitätspolitik von Bereket Fide: gesunde Pflanzen, rückverfolgbare Produktion.',NULL,'Qualitätspolitik | Bereket Fide','Qualitätspolitik und Produktionsverpflichtungen von Bereket Fide.','qualitätspolitik, gemüsepflanzen, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020014-6014-4014-a014-cccccccc0014','bc010007-5007-4007-9007-cccccccc0007','tr','Hizmet Politikamız','hizmet-politikasi','{\"html\": \"<h2>Hizmet Politikamız</h2><p>Müşterilerimize açık iletişim, şeffaf süreç ve teknik destek sunmayı hedefliyoruz.</p><h3>Teklif ve sipariş</h3><p>Teklif talepleri değerlendirilir; nihai koşullar yazılı teyit ile netleşir. Üretim ve sevkiyat planlaması müşteri ihtiyacına ve mevsim dinamiklerine göre yapılır.</p><h3>Destek</h3><p>Çeşit seçimi, dikim önerileri ve teslimat ile ilgili sorularda ekiplerimizle iletişime geçebilirsiniz.</p><h3>Şikâyet ve geri bildirim</h3><p>Geri bildirimlerinizi <strong>info@bereketfide.com.tr</strong> üzerinden iletmenizi rica ederiz; kayıt altına alınır ve ilgili birimlere yönlendirilir.</p><p><em>Son güncelleme: Nisan 2026</em></p>\"}','Bereket Fide hizmet politikası: iletişim, teklif süreci ve müşteri desteği.',NULL,'Hizmet Politikası | Bereket Fide','Bereket Fide hizmet politikası ve müşteri süreçleri.','hizmet politikası, müşteri hizmetleri, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020015-6015-4015-a015-cccccccc0015','bc010007-5007-4007-9007-cccccccc0007','en','Service Policy','service-policy','{\"html\": \"<h2>Service Policy</h2><p>We aim to provide clear communication, transparent processes, and technical support to our customers.</p><h3>Quotes and orders</h3><p>Quote requests are evaluated; final conditions are confirmed in writing. Production and shipment planning follows customer needs and seasonal dynamics.</p><h3>Support</h3><p>Contact our teams for variety selection, planting guidance, and delivery-related questions.</p><h3>Feedback</h3><p>Please send feedback to <strong>info@bereketfide.com.tr</strong>; it is logged and routed to the relevant teams.</p><p><em>Last updated: April 2026</em></p>\"}','Bereket Fide service policy: communication, quoting, and customer support.',NULL,'Service Policy | Bereket Fide','Bereket Fide service policy and customer processes.','service policy, customer support, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020016-6016-4016-a016-cccccccc0016','bc010007-5007-4007-9007-cccccccc0007','de','Servicepolitik','servicepolitik','{\"html\": \"<h2>Servicepolitik</h2><p>Wir möchten unseren Kundinnen und Kunden klare Kommunikation, transparente Abläufe und technische Unterstützung bieten.</p><h3>Angebote und Bestellungen</h3><p>Anfragen werden geprüft; endgültige Bedingungen werden schriftlich bestätigt. Produktion und Versandplanung richten sich nach Kundenbedarf und Saisondynamik.</p><h3>Support</h3><p>Wenden Sie sich an unsere Teams bei Sortenwahl, Anbauhinweisen und Fragen zur Lieferung.</p><h3>Feedback</h3><p>Feedback senden Sie bitte an <strong>info@bereketfide.com.tr</strong>; es wird erfasst und weitergeleitet.</p><p><em>Stand: April 2026</em></p>\"}','Servicepolitik von Bereket Fide: Kommunikation, Angebote und Support.',NULL,'Servicepolitik | Bereket Fide','Servicepolitik und Kundenprozesse bei Bereket Fide.','servicepolitik, kundenservice, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020017-6017-4017-a017-cccccccc0017','bc010008-5008-4008-9008-cccccccc0008','tr','İnsan Kaynakları','insan-kaynaklari','{\"html\": \"<h2>İnsan Kaynakları</h2><p>Bereket Fide, üretim ve operasyon süreçlerinde görev alacak adayları; güven, sürekli öğrenme ve ekip çalışması değerleriyle bir araya getirmeyi hedefler.</p><p>Güncel iş ilanları ve başvuru süreçleri için iletişim kanallarımızdan bize ulaşabilir veya <strong>info@bereketfide.com.tr</strong> adresine özgeçmişinizi iletebilirsiniz.</p>\"}','Bereket Fide insan kaynakları ve başvuru bilgileri.',NULL,'İnsan Kaynakları | Bereket Fide','Bereket Fide iş başvurusu ve kariyer iletişim bilgileri.','insan kaynakları, kariyer, iş başvurusu, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020018-6018-4018-a018-cccccccc0018','bc010008-5008-4008-9008-cccccccc0008','en','Careers','careers','{\"html\": \"<h2>Careers</h2><p>Bereket Fide brings together people who want to grow with us in production and operations, guided by trust, continuous learning and teamwork.</p><p>For open roles and applications, please reach us through our contact channels or send your CV to <strong>info@bereketfide.com.tr</strong>.</p>\"}','Careers at Bereket Fide — how to apply.',NULL,'Careers | Bereket Fide','Careers and job applications at Bereket Fide.','careers, jobs, human resources, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020019-6019-4019-a019-cccccccc0019','bc010008-5008-4008-9008-cccccccc0008','de','Karriere','karriere','{\"html\": \"<h2>Karriere</h2><p>Bereket Fide sucht Menschen für Produktion und Betrieb, die mit uns wachsen möchten — auf Basis von Vertrauen, kontinuierlichem Lernen und Teamarbeit.</p><p>Für offene Stellen und Bewerbungen erreichen Sie uns über die Kontaktwege oder senden Sie Ihre Unterlagen an <strong>info@bereketfide.com.tr</strong>.</p>\"}','Karriere bei Bereket Fide — Bewerbung.',NULL,'Karriere | Bereket Fide','Karriere und Bewerbungen bei Bereket Fide.','karriere, jobs, personal, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020020-6020-4020-a020-cccccccc0020','bc010001-5001-4001-9001-cccccccc0001','de','Über uns','about','{\"html\": \"<p>Unser Schwerpunkt liegt auf <strong>qualitativ hochwertiger und ertragreicher Jungpflanzenproduktion</strong>: veredelte und Standard-Jungpflanzen in modernen Gewächshäusern, mit erneuerbarer Energie aus eigenen Solarmodulen.</p><h2>Über Bereket Fide</h2><p>Bereket Fide wurde 2006 in Çamköy, Aksu (Antalya), gegründet, um den regionalen Bedarf an Jungpflanzen zu decken. Heute produzieren wir auf insgesamt 32.000 m² Fläche, davon 24.000 m² in modernen, computergesteuerten Gewächshäusern.</p><p>Mit einer jährlichen Kapazität von 16–17 Millionen veredelten und 18–20 Millionen unveredelten Jungpflanzen zählt unser Standort zu den modernsten Produktionszentren der Region.</p><h2>Technologie und Produktion</h2><p>Sämtliche Abläufe werden über computergesteuerte Bewässerung, Düngung, Heizung und Befeuchtung geführt. Im Einklang mit umweltbewusster Produktion decken wir den Energiebedarf der Anlage über eigene Solarmodule (erneuerbare Energie).</p><h2>Unsere Qualitätspolitik</h2><p>Wir wollen Kundenzufriedenheit auf hohem Niveau halten, indem wir sich wandelnde Anforderungen mit einer technologie- und innovationsorientierten Vertriebsstrategie begleiten. Gemeinsam mit Lieferanten und Team entwickeln wir uns weiter – mit hohem sozialen Verantwortungsbewusstsein und Umweltbewusstsein.</p>\"}','Hochwertige Jungpflanzen in modernen Gewächshäusern; 24.000 m² computergesteuerte Produktion in Antalya Aksu mit erneuerbarer Energie.',NULL,'Über uns | Bereket Fide','Bereket Fide: Qualität, moderne Gewächshäuser und Solarstrom in Antalya Aksu seit 2006.','bereket fide, über uns, jungpflanzen, antalya, veredelung','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020021-6021-4021-a021-cccccccc0021','bc010002-5002-4002-9002-cccccccc0002','de','Datenschutzerklärung','privacy','{\"html\": \"<h2>Datenschutzerklärung</h2><p>Bereket Fide Tarım San. ve Tic. Ltd. Şti. (<strong>Bereket Fide</strong>) verpflichtet sich zum Schutz personenbezogener Daten, die über <strong>www.bereketfide.com.tr</strong> erhoben werden. Diese Erklärung beschreibt, welche Daten wir erheben, wofür wir sie nutzen und wie wir sie schützen.</p><h3>1. Erhobene Daten</h3><p>Beim Besuch der Website und bei Formularnutzung können folgende Daten anfallen:</p><ul><li><strong>Identität:</strong> Vor- und Nachname, Firmenname</li><li><strong>Kontakt:</strong> E-Mail, Telefon, Adresse</li><li><strong>Anfragen:</strong> Produktpräferenzen, Mengen und Lieferhinweise aus dem Angebotsformular</li><li><strong>Technisch:</strong> IP-Adresse, Browsertyp, besuchte Seiten, Cookie-Daten</li></ul><h3>2. Zwecke</h3><ul><li>Bearbeitung und Beantwortung von Angebotsanfragen</li><li>Abwicklung von Bestellungen und Logistikplanung</li><li>Information über Produkte und Dienstleistungen</li><li>Verbesserung und Analyse der Website</li><li>Erfüllung gesetzlicher Pflichten</li></ul><h3>3. Weitergabe</h3><p>Eine Weitergabe an Dritte erfolgt ohne Ihre ausdrückliche Zustimmung nicht, ausgenommen gesetzliche Pflichten oder eingeschränkt an Dienstleister (Hosting, E-Mail, Logistik).</p><h3>4. Sicherheit</h3><p>Wir setzen SSL-Verschlüsselung, Firewalls und regelmäßige Updates ein; technische und organisatorische Maßnahmen schützen vor unbefugtem Zugriff.</p><h3>5. Cookies</h3><p>Wir verwenden Cookies zur Verbesserung der Nutzung. Details finden Sie in unserer Cookie-Richtlinie.</p><h3>6. Ihre Rechte</h3><p>Nach türkischem Datenschutzrecht (KVKK Nr. 6698) haben Sie unter anderem Recht auf Auskunft, Berichtigung, Löschung, Einschränkung der Verarbeitung, Datenübertragbarkeit und Widerspruch.</p><h3>7. Kontakt</h3><p>Fragen zum Datenschutz: <strong>info@bereketfide.com.tr</strong></p><p><em>Stand: April 2026</em></p>\"}','Datenschutz bei Bereket Fide: Erhebung, Nutzung und Schutz personenbezogener Daten.',NULL,'Datenschutz | Bereket Fide','Datenschutzerklärung und Grundsätze der Datenverarbeitung bei Bereket Fide.','datenschutz, kvkk, personenbezogene daten, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020022-6022-4022-a022-cccccccc0022','bc010003-5003-4003-9003-cccccccc0003','de','Nutzungsbedingungen','terms','{\"html\": \"<h2>Nutzungsbedingungen</h2><p>Mit der Nutzung von <strong>www.bereketfide.com.tr</strong> (<strong>Website</strong>) erkennen Sie die folgenden Bedingungen an.</p><h3>1. Allgemeines</h3><p>Die Website wird von Bereket Fide Tarım San. ve Tic. Ltd. Şti. betrieben. Sämtliche Inhalte (Texte, Bilder, Logos, Grafiken, Videos) sind Eigentum von Bereket Fide und urheberrechtlich geschützt.</p><h3>2. Geistiges Eigentum</h3><p>Vervielfältigung, Verbreitung oder Veränderung ohne Zustimmung ist untersagt und kann rechtliche Schritte nach sich ziehen.</p><h3>3. Produktinformationen</h3><p>Angaben zu Produkten, Preisen und Technik dienen der Information; Änderungen sind vorbehalten. Für verbindliche Preise und Verfügbarkeit kontaktieren Sie uns bitte direkt.</p><h3>4. Angebote und Bestellungen</h3><p>Anfragen über die Website sind unverbindlich; Bestellungen werden erst nach schriftlicher Bestätigung wirksam.</p><h3>5. Haftung</h3><ul><li>Wir bemühen uns um richtige Angaben, übernehmen jedoch keine Gewähr für Vollständigkeit.</li><li>Für Inhalte externer Links sind wir nicht verantwortlich.</li><li>Keine Haftung für vorübergehende Nichterreichbarkeit (Wartung, technische Störungen, höhere Gewalt).</li></ul><h3>6. Anwendbares Recht</h3><p>Es gilt das Recht der Republik Türkei; für Streitigkeiten sind die Gerichte und Vollstreckungsstellen in Antalya zuständig.</p><h3>7. Kontakt</h3><p><strong>info@bereketfide.com.tr</strong></p><p><em>Stand: April 2026</em></p>\"}','Nutzungsbedingungen der Website Bereket Fide.',NULL,'Nutzungsbedingungen | Bereket Fide','Nutzungsbedingungen, Urheberrecht und rechtliche Hinweise.','nutzungsbedingungen, recht, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020023-6023-4023-a023-cccccccc0023','bc010004-5004-4004-9004-cccccccc0004','de','Hinweis zum Datenschutz (KVKK)','kvkk-aydinlatma-metni','{\"html\": \"<h2>Hinweis zum Datenschutz</h2><p>Gemäß dem türkischen Gesetz Nr. 6698 zum Schutz personenbezogener Daten (KVKK) informiert Sie Bereket Fide Tarım San. ve Tic. Ltd. Şti. als verantwortliche Stelle über die Verarbeitung Ihrer Daten.</p><h3>Daten und Zwecke</h3><p>Im Rahmen von Kontaktformularen, Angebotsanfragen und Bestellprozessen verarbeitete Identitäts-, Kontakt- und anfragebezogene Daten dienen der Bearbeitung Ihrer Anfragen, Vertragserfüllung, Kundenbetreuung und gesetzlichen Pflichten.</p><h3>Rechtsgrundlage und Weitergabe</h3><p>Die Verarbeitung kann auf Vertragserfüllung, gesetzliche Pflicht und berechtigtes Interesse gestützt sein; eine Weitergabe erfolgt eingeschränkt an Dienstleister oder Behörden, sofern gesetzlich erforderlich.</p><h3>Ihre Rechte</h3><p>Sie haben nach KVKK unter anderem Auskunfts-, Berichtigungs-, Löschungs- und Widerspruchsrechte sowie Rechte auf Datenübertragbarkeit und Einschränkung der Verarbeitung.</p><h3>Kontakt</h3><p><strong>info@bereketfide.com.tr</strong></p><p><em>Stand: April 2026</em></p>\"}','KVKK-Datenschutzhinweis: Zwecke und Betroffenenrechte.',NULL,'Datenschutzhinweis (KVKK) | Bereket Fide','Information zur Verarbeitung personenbezogener Daten nach türkischem KVKK.','kvkk, datenschutz, personenbezogene daten, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('bc020024-6024-4024-a024-cccccccc0024','bc010005-5005-4005-9005-cccccccc0005','de','Cookie-Richtlinie','cookies','{\"html\": \"<h2>Cookie-Richtlinie</h2><p>Diese Richtlinie erläutert den Einsatz von Cookies auf <strong>www.bereketfide.com.tr</strong>.</p><h3>Was sind Cookies?</h3><p>Cookies sind kleine Textdateien in Ihrem Browser; sie können zur Messung der Nutzung, zur Speicherung von Einstellungen und zur Unterstützung der Sicherheit dienen.</p><h3>Arten</h3><ul><li><strong>Notwendig:</strong> für grundlegende Funktionen der Website</li><li><strong>Funktional / Präferenz:</strong> z. B. Sprache oder Formularzustand</li><li><strong>Statistik (falls aktiv):</strong> anonymisierte oder aggregierte Auswertungen</li></ul><h3>Verwaltung</h3><p>Sie können Cookies in den Browsereinstellungen löschen oder blockieren; einige Funktionen können eingeschränkt sein.</p><h3>Kontakt</h3><p><strong>info@bereketfide.com.tr</strong></p><p><em>Stand: April 2026</em></p>\"}','Cookie-Nutzung und Verwaltung bei Bereket Fide.',NULL,'Cookie-Richtlinie | Bereket Fide','Cookies auf der Website von Bereket Fide.','cookies, datenschutz, bereket fide','2026-04-13 23:18:21.512','2026-04-13 23:18:21.512');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020001-6001-4001-a001-nnnnnnnn0001','nw010001-5001-4001-9001-nnnnnnnn0001','tr','Tarım Bakanlığı BÜGEM GMY İhsan Emiralioğlu Bereket Fide\'yi Ziyaret Etti','bugem-gmy-ihsan-emiralioglu-bereketfide-ziyareti','{\"html\":\"<p>Tarım ve Orman Bakanlığı Bitkisel Üretim Genel Müdürlüğü (BÜGEM) Genel Müdür Yardımcısı İhsan Emiralioğlu, Bereket Fide tesislerimizi ziyaret etti. Misafirimize modern fide üretim süreçlerimizi, bilgisayar kontrollü seralarımızı ve sektöre katkılarımızı tanıttık.</p><p>Ziyaret kapsamında yerli tohum ve fide üretiminin güçlendirilmesi, üretici destekleri ve sektörel iş birliği olanakları üzerine verimli bir görüşme gerçekleştirildi. Değerli ziyaretleri için Sayın Emiralioğlu\'na teşekkür ederiz.</p>\"}','BÜGEM Genel Müdür Yardımcısı İhsan Emiralioğlu, Bereket Fide üretim tesislerini ziyaret etti.',NULL,'BÜGEM GMY İhsan Emiralioğlu Ziyareti | Bereket Fide','Tarım Bakanlığı BÜGEM Genel Müdür Yardımcısı İhsan Emiralioğlu\'nun Bereket Fide ziyareti ve sektörel değerlendirmeleri.','bügem, tarım bakanlığı, ihsan emiralioğlu, ziyaret, bereket fide, fide üretimi','2026-04-13 23:18:21.581','2026-04-15 18:34:02.492');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020002-6002-4002-a002-nnnnnnnn0002','nw010002-5002-4002-9002-nnnnnnnn0002','tr','Türktob Başkanı Kayhan Yıldırım ile Sektör Değerlendirmesi','turktob-baskani-kayhan-yildirim-bereketfide-ziyareti','{\"html\": \"<p>Türkiye Tohumcular Birliği (Türktob) Başkanı Kayhan Yıldırım, Bereket Fide\'yi ziyaret etti. Türk tohumculuk sektörünün gündemine ilişkin görüşler paylaşıldı; yerli üretimin büyümesi, ihracat fırsatları ve sektörün karşılaştığı yapısal meseleler değerlendirildi.</p><p>Birliğin çalışmaları ve sektöre yönelik politika önerileri kapsamında gerçekleştirilen bu buluşmadan memnuniyet duyduk. Değerli ziyaretleri için Sayın Yıldırım\'a teşekkür ederiz.</p>\"}','Türktob Başkanı Kayhan Yıldırım Bereket Fide ile bir araya gelerek sektörü değerlendirdi.',NULL,'Türktob Başkanı Kayhan Yıldırım Ziyareti | Bereket Fide','Türkiye Tohumcular Birliği Başkanı Kayhan Yıldırım\'ın Bereket Fide ziyareti ve tohumculuk sektörü değerlendirmesi.','türktob, kayhan yıldırım, tohumculuk, ziyaret, bereket fide, sektör','2026-04-13 23:18:21.581','2026-04-13 23:18:21.581');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020003-6003-4003-a003-nnnnnnnn0003','nw010003-5003-4003-9003-nnnnnnnn0003','tr','Bereket Fide Tarla Günleri Bu Ay Başlıyor','bereket-fide-tarla-gunleri-basliyor','{\"html\": \"<p>Üreticilerimizle sahada bir araya geleceğimiz tarla günü programımız bu ay başlıyor. Etkinliklerde çeşit performansı, sulama ve besleme stratejileri ile mevsimsel risklere karşı öneriler paylaşılacak.</p><p>Katılım ve tarih bilgisi için bölge sorumlularımız veya <strong>info@bereketfide.com.tr</strong> üzerinden iletişime geçebilirsiniz.</p>\"}','Sahada üretici buluşmaları: tarla günleri bu ay başlıyor.',NULL,'Tarla Günleri | Bereket Fide','Bereket Fide tarla günleri: çeşit performansı ve sezon uygulamaları ile saha buluşmaları.','tarla günleri, etkinlik, üretici buluşması, fide','2026-04-13 23:18:21.581','2026-04-13 23:18:21.581');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020004-6004-4004-a004-nnnnnnnn0004','nw010004-5004-4004-9004-nnnnnnnn0004','tr','Üretim Hatlarımızı Genişlettik: Kapasite ve Lojistik Güçlendi','uretim-hatlari-genisleme-kapasite-lojistik','{\"html\": \"<p>Antalya Aksu tesislerimizde yürütülen yatırımlarla üretim hatlarımızı ve depolama altyapımızı genişlettik. Bilgisayar kontrollü seralarımızda operasyonlarımız, on milyonlarca fideyi kapsayacak ölçekte sürdürülmektedir.</p><p>Sevkiyat planlaması ve sipariş yoğunluğu dönemlerinde daha esnek hizmet sunmayı hedefliyoruz; güncel teslim süreleri için satış ekibimizle iletişime geçebilirsiniz.</p>\"}','Tesis yatırımı ile kapasite ve lojistikte güçlenme.',NULL,'Kapasite ve Yatırım | Bereket Fide','Bereket Fide üretim hatları ve lojistik altyapısındaki genişleme duyurusu.','kapasite, yatırım, lojistik, fide üretimi','2026-04-13 23:18:21.581','2026-04-13 23:18:21.581');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020005-6005-4005-a005-nnnnnnnn0005','nw010005-5005-4005-9005-nnnnnnnn0005','tr','Geleceğin Tarımı İçin Genç Çiftçilere Destek','genc-ciftci-destek-projeleri','{\"html\": \"<p>Tarımın sürdürülebilirliği için genç üreticilerin bilgiye ve güvenilir fide kaynağına erişimini önemsiyoruz. Programlarımız kapsamında çeşit seçimi, dikim takvimi ve ilk sezon yönetimi konularında yönlendirme sunuyoruz.</p><p>Genç çiftçi girişimleri ve kooperatif iş birlikleri için özel iletişim hattımız üzerinden taleplerinizi iletebilirsiniz.</p>\"}','Genç üreticilere çeşit ve sezon danışmanlığı.',NULL,'Genç Çiftçilere Destek | Bereket Fide','Genç çiftçilere fide üreticisi olarak teknik ve çeşit desteği.','genç çiftçi, tarım geleceği, danışmanlık','2026-04-13 23:18:21.581','2026-04-13 23:18:21.581');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020006-6006-4006-a006-nnnnnnnn0006','nw010001-5001-4001-9001-nnnnnnnn0001','en','BÜGEM Deputy Director General İhsan Emiralioğlu Visits Bereket Fide','bugem-deputy-director-ihsan-emiralioglu-bereketfide-visit','{\"html\": \"<p>İhsan Emiralioğlu, Deputy Director General of the Directorate General of Plant Production (BÜGEM) under the Ministry of Agriculture and Forestry, visited Bereket Fide. We presented our modern seedling production processes, computer-controlled greenhouses and contributions to the sector.</p><p>The meeting covered strengthening domestic seed and seedling production, producer support schemes, and opportunities for sectoral cooperation. We thank Mr. Emiralioğlu for his valuable visit.</p>\"}','BÜGEM Deputy Director General İhsan Emiralioğlu visited Bereket Fide production facilities.',NULL,'BÜGEM Deputy Director Emiralioğlu Visit | Bereket Fide','Visit of Ministry of Agriculture BÜGEM Deputy Director General İhsan Emiralioğlu to Bereket Fide and sectoral assessments.','bügem, ministry of agriculture, ihsan emiralioglu, visit, bereket fide, seedling production','2026-04-13 23:18:21.583','2026-04-13 23:18:21.583');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020007-6007-4007-a007-nnnnnnnn0007','nw010002-5002-4002-9002-nnnnnnnn0002','en','Türktob President Kayhan Yıldırım and Bereket Fide on the Sector','turktob-president-kayhan-yildirim-bereketfide-visit','{\"html\": \"<p>Kayhan Yıldırım, President of the Turkish Seedsmen Association (Türktob), visited Bereket Fide. Views were shared on the agenda of the Turkish seed sector, including the growth of domestic production, export opportunities and structural challenges facing the industry.</p><p>We were pleased to host this meeting in the context of the association\'s work and policy recommendations for the sector. We thank Mr. Yıldırım for his valuable visit.</p>\"}','Türktob President Kayhan Yıldırım met with Bereket Fide to assess the seedsmen sector.',NULL,'Türktob President Kayhan Yıldırım Visit | Bereket Fide','Visit of Turkish Seedsmen Association President Kayhan Yıldırım to Bereket Fide and seed sector assessment.','türktob, kayhan yildirim, seed sector, visit, bereket fide','2026-04-13 23:18:21.583','2026-04-13 23:18:21.583');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020008-6008-4008-a008-nnnnnnnn0008','nw010003-5003-4003-9003-nnnnnnnn0003','en','Bereket Fide Field Days Start This Month','bereket-fide-field-days-start-this-month','{\"html\": \"<p>Our field day program, where we meet growers on site, starts this month. We will share variety performance, irrigation and nutrition strategies, and seasonal risk management tips.</p><p>Contact your regional representative or <strong>info@bereketfide.com.tr</strong> for dates and attendance details.</p>\"}','On-farm meetings with growers: field days start this month.',NULL,'Field Days | Bereket Fide','Bereket Fide field days: variety performance and seasonal practices with growers.','field days, event, grower meeting, seedlings','2026-04-13 23:18:21.583','2026-04-13 23:18:21.583');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020009-6009-4009-a009-nnnnnnnn0009','nw010004-5004-4004-9004-nnnnnnnn0004','en','We Expanded Production Lines: Capacity and Logistics Strengthened','production-lines-expanded-capacity-logistics','{\"html\": \"<p>Investments at our Antalya Aksu facility have expanded our production lines and storage infrastructure. Operations in our computer-controlled greenhouses continue at a scale serving tens of millions of seedlings per year.</p><p>We aim to offer more flexible service during peak order periods; contact our sales team for current lead times.</p>\"}','Facility investment strengthens capacity and logistics.',NULL,'Capacity and Investment | Bereket Fide','Bereket Fide announces expanded production and logistics capacity.','capacity, investment, logistics, seedling production','2026-04-13 23:18:21.583','2026-04-13 23:18:21.583');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020010-6010-4010-a010-nnnnnnnn0010','nw010005-5005-4005-9005-nnnnnnnn0005','en','Support for Young Farmers for the Future of Agriculture','support-for-young-farmers','{\"html\": \"<p>We care that young growers access knowledge and reliable seedling sources for sustainable agriculture. Through our programs we provide guidance on variety selection, planting calendars and first-season management.</p><p>Young farmer initiatives and cooperative partnerships can reach us through our dedicated contact channel.</p>\"}','Guidance on varieties and the growing season for young producers.',NULL,'Support for Young Farmers | Bereket Fide','Bereket Fide support for young farmers: technical and variety advice.','young farmer, future of agriculture, advisory','2026-04-13 23:18:21.583','2026-04-13 23:18:21.583');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020011-6011-4011-a011-nnnnnnnn0011','nw010001-5001-4001-9001-nnnnnnnn0001','de','BÜGEM-Vizedirektor İhsan Emiralioğlu besucht Bereket Fide','bugem-vizedirektor-ihsan-emiralioglu-bereketfide-besuch','{\"html\": \"<p>İhsan Emiralioğlu, Vizedirektor der Generaldirektion für pflanzliche Produktion (BÜGEM) im türkischen Landwirtschaftsministerium, besuchte Bereket Fide. Wir stellten unsere modernen Jungpflanzenproduktionsprozesse, computergesteuerten Gewächshäuser und Beiträge zum Sektor vor.</p><p>Im Mittelpunkt des Gesprächs standen die Stärkung der inländischen Samen- und Jungpflanzenproduktion, Erzeugerförderprogramme sowie Möglichkeiten der sektoralen Zusammenarbeit. Wir danken Herrn Emiralioğlu für seinen wertvollen Besuch.</p>\"}','BÜGEM-Vizedirektor İhsan Emiralioğlu besuchte die Produktionsstätten von Bereket Fide.',NULL,'BÜGEM-Besuch Emiralioğlu | Bereket Fide','Besuch des BÜGEM-Vizedirektors İhsan Emiralioğlu bei Bereket Fide und sektorale Einschätzungen.','bügem, Landwirtschaftsministerium, ihsan emiralioglu, Besuch, bereket fide, Jungpflanzen','2026-04-13 23:18:21.585','2026-04-13 23:18:21.585');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020012-6012-4012-a012-nnnnnnnn0012','nw010002-5002-4002-9002-nnnnnnnn0002','de','Türktob-Präsident Kayhan Yıldırım und Bereket Fide zur Branchenlage','turktob-praesident-kayhan-yildirim-bereketfide-besuch','{\"html\": \"<p>Kayhan Yıldırım, Präsident des Türkischen Saatgutverbandes (Türktob), besuchte Bereket Fide. Es wurden Ansichten zur Agenda der türkischen Saatgutbranche ausgetauscht, darunter das Wachstum der Inlandsproduktion, Exportchancen und strukturelle Herausforderungen des Sektors.</p><p>Wir freuten uns, dieses Treffen im Rahmen der Verbandsarbeit und der politischen Empfehlungen für den Sektor zu empfangen. Wir danken Herrn Yıldırım für seinen wertvollen Besuch.</p>\"}','Türktob-Präsident Kayhan Yıldırım traf Bereket Fide zur Bewertung der Saatgutbranche.',NULL,'Türktob-Präsident Yıldırım Besuch | Bereket Fide','Besuch des Türktob-Präsidenten Kayhan Yıldırım bei Bereket Fide und Einschätzung der Saatgutbranche.','türktob, kayhan yildirim, Saatgutbranche, Besuch, bereket fide','2026-04-13 23:18:21.585','2026-04-13 23:18:21.585');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020013-6013-4013-a013-nnnnnnnn0013','nw010003-5003-4003-9003-nnnnnnnn0003','de','Bereket Fide Feldtage starten in diesem Monat','bereket-fide-feldtage-start','{\"html\": \"<p>Unser Feldtag-Programm, bei dem wir Betriebe vor Ort treffen, beginnt in diesem Monat. Wir teilen Sortenleistung, Bewässerungs- und Düngestrategien sowie Hinweise zum saisonalen Risikomanagement.</p><p>Termine und Teilnahme erfragen Sie bei Ihrem Regionalansprechpartner oder unter <strong>info@bereketfide.com.tr</strong>.</p>\"}','Feldtage mit Produzenten starten in diesem Monat.',NULL,'Feldtage | Bereket Fide','Bereket Fide Feldtage: Sortenleistung und Saisonpraxis vor Ort.','Feldtage, Veranstaltung, Betriebstreffen, Jungpflanzen','2026-04-13 23:18:21.585','2026-04-13 23:18:21.585');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020014-6014-4014-a014-nnnnnnnn0014','nw010004-5004-4004-9004-nnnnnnnn0004','de','Produktionslinien erweitert: Kapazität und Logistik gestärkt','produktionslinien-erweiterung-kapazitaet-logistik','{\"html\": \"<p>Investitionen am Standort Antalya Aksu haben unsere Produktionslinien und Lagerinfrastruktur erweitert. Der Betrieb in unseren computergesteuerten Gewächshäusern erfolgt in einem Umfang von vielen Millionen Jungpflanzen pro Jahr.</p><p>In Spitzenzeiten der Nachfrage wollen wir flexibler liefern; aktuelle Lieferzeiten erhalten Sie vom Vertrieb.</p>\"}','Anlageninvestition stärkt Kapazität und Logistik.',NULL,'Kapazität und Investition | Bereket Fide','Bereket Fide meldet erweiterte Produktions- und Logistikkapazität.','Kapazität, Investition, Logistik, Jungpflanzenproduktion','2026-04-13 23:18:21.585','2026-04-13 23:18:21.585');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020015-6015-4015-a015-nnnnnnnn0015','nw010005-5005-4005-9005-nnnnnnnn0005','de','Unterstützung junger Landwirte für die Zukunft der Landwirtschaft','unterstuetzung-junge-landwirte','{\"html\": \"<p>Uns ist wichtig, dass junge Betriebe Wissen und zuverlässige Jungpflanzen-Quellen für eine nachhaltige Landwirtschaft finden. In unseren Programmen beraten wir zu Sortenwahl, Pflanzkalender und Management in der ersten Saison.</p><p>Initiativen junger Landwirte und Genossenschaftspartnerschaften können uns über den dafür vorgesehenen Kontakt erreichen.</p>\"}','Beratung zu Sorten und Saison für junge Produzenten.',NULL,'Unterstützung junger Landwirte | Bereket Fide','Bereket Fide unterstützt junge Landwirte mit Fach- und Sortenberatung.','junger Landwirt, Zukunft Landwirtschaft, Beratung','2026-04-13 23:18:21.585','2026-04-13 23:18:21.585');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020016-6016-4016-a016-nnnnnnnn0016','nw010006-5006-4006-9006-nnnnnnnn0006','tr','Bereket Fide\'ye Ziyaret ve Sektörel Değerlendirme','antalya-valiligi-aksu-bereketfide-ziyareti','{\"html\": \"<p>Antalya Valimiz, Aksu Kaymakamımız, Aksu Belediye Başkanımız, İl Tarım ve Orman Müdürümüz ile İlçe Tarım ve Orman Müdürümüz ve beraberindeki heyet, Bereket Fide bünyesinde hizmete giren yeni işletme binamıza ziyarette bulunmuştur.</p><p>Gerçekleştirilen nazik ziyaret kapsamında, sektörümüzde karşılaşılan güncel sorunlar ve çözüm önerileri hakkında görüş alışverişinde bulunulmuş, aynı zamanda taleplerimiz ilgili yetkililere iletilmiştir. Program çerçevesinde üretim tesisimizde kısa bir tanıtım ve bilgilendirme gezisi de gerçekleştirilmiştir.</p><p>Ziyaretlerinden dolayı tüm sayın yetkililere teşekkür ederiz.</p>\"}','Antalya Valimiz ve Aksu yöneticileri, yeni işletme binamızı ziyaret ederek sektörel değerlendirmelerde bulundu.',NULL,'Antalya Valiliği Ziyareti | Bereket Fide','Antalya Valisi, Aksu Kaymakamı, Aksu Belediye Başkanı ve Tarım Orman Müdürlerinin Bereket Fide yeni binası ziyareti.','antalya, valilik, aksu, ziyaret, bereket fide, sektör değerlendirme','2026-04-13 23:18:21.581','2026-04-13 23:18:21.581');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020017-6017-4017-a017-nnnnnnnn0017','nw010006-5006-4006-9006-nnnnnnnn0006','en','A Visit to Bereket Fide and Sectoral Assessment','antalya-governorship-aksu-bereketfide-visit','{\"html\": \"<p>The Governor of Antalya, the District Governor of Aksu, the Mayor of Aksu, the Provincial and District Directors of Agriculture and Forestry, and their accompanying delegation visited our new headquarters building that has recently entered service at Bereket Fide.</p><p>During the courtesy visit, opinions were exchanged on current challenges facing our sector and proposed solutions, and our requests were conveyed to the relevant authorities. As part of the programme, a brief introductory tour of our production facility was also conducted.</p><p>We sincerely thank all distinguished officials for their visit.</p>\"}','The Governor of Antalya and Aksu officials visited our new headquarters and assessed the sector.',NULL,'Antalya Governorship Visit | Bereket Fide','Visit of the Governor of Antalya, District Governor of Aksu, Mayor of Aksu and Agriculture Directors to the new Bereket Fide building.','antalya, governorship, aksu, visit, bereket fide, sector assessment','2026-04-13 23:18:21.583','2026-04-13 23:18:21.583');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020018-6018-4018-a018-nnnnnnnn0018','nw010006-5006-4006-9006-nnnnnnnn0006','de','Besuch bei Bereket Fide und sektorale Bewertung','antalya-regierung-aksu-bereketfide-besuch','{\"html\": \"<p>Der Gouverneur von Antalya, der Bezirksgouverneur von Aksu, der Bürgermeister von Aksu, die Leitungen der Provinz- und Bezirkslandwirtschaftsämter sowie ihre Delegation besuchten unser neues Verwaltungsgebäude, das bei Bereket Fide seinen Betrieb aufgenommen hat.</p><p>Im Rahmen des freundlichen Besuchs wurden aktuelle Herausforderungen der Branche und Lösungsvorschläge erörtert; gleichzeitig wurden unsere Anliegen an die zuständigen Behörden übermittelt. Im Programm war auch ein kurzer Informationsrundgang durch unsere Produktionsanlage enthalten.</p><p>Wir danken allen geschätzten Offiziellen herzlich für ihren Besuch.</p>\"}','Der Gouverneur von Antalya und die Verwaltung Aksu besuchten unsere neue Zentrale und bewerteten die Branchenlage.',NULL,'Besuch der Antalya-Regierung | Bereket Fide','Besuch des Gouverneurs von Antalya, des Bezirksgouverneurs von Aksu, des Bürgermeisters von Aksu und der Landwirtschaftsdirektoren im neuen Bereket Fide Gebäude.','Antalya, Regierung, Aksu, Besuch, Bereket Fide, Branchenbewertung','2026-04-13 23:18:21.585','2026-04-13 23:18:21.585');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020019-6019-4019-a019-nnnnnnnn0019','nw010007-5007-4007-9007-nnnnnnnn0007','tr','Samsun Heyetinden Bereket Fide\'ye Ziyaret','samsun-valisi-heyeti-bereketfide-ziyareti','{\"html\": \"<p>Samsun Valimiz Sayın Doç. Dr. Zülkif Dağlı, beraberinde Bafra Kaymakamı Cevdet Ertürkmen, Bafra Belediye Başkanı Hamit Kılıç, Bafra Ticaret ve Sanayi Odası, Bafra Ticaret Borsası, Bafra Ziraat Odası, Bafra Sera OSB yöneticileri ile Antalya İl Tarım ve Orman Müdürlüğü İl Müdür Yardımcısı Gökhan Karaca, Aksu İlçe Tarım ve Orman Müdürü İhsan İnal ve emniyet mensuplarından oluşan heyet, Bereket Fide üretim tesisimizi ziyaret etmiştir.</p><p>Gerçekleştirilen ziyaret kapsamında, genel yetiştiricilik faaliyetlerimiz ve ihracat çalışmalarımız hakkında karşılıklı bilgi alışverişinde bulunulmuş, sektörün mevcut durumu üzerine istişareler yapılmıştır.</p><p>Nazik ziyaretlerinden dolayı kendilerine teşekkür ederiz.</p>\"}','Samsun Valisi Doç. Dr. Zülkif Dağlı ve Bafra heyeti, Bereket Fide üretim tesisini ziyaret ederek sektörel istişarelerde bulundu.',NULL,'Samsun Valisi Ziyareti | Bereket Fide','Samsun Valisi Zülkif Dağlı ve Bafra heyetinin Bereket Fide üretim tesisi ziyareti ve sektörel değerlendirmesi.','samsun, valilik, bafra, ziyaret, bereket fide, ihracat, sera osb','2026-04-13 23:18:21.581','2026-04-13 23:18:21.581');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020020-6020-4020-a020-nnnnnnnn0020','nw010007-5007-4007-9007-nnnnnnnn0007','en','A Delegation from Samsun Visits Bereket Fide','samsun-governor-delegation-bereketfide-visit','{\"html\": \"<p>Governor of Samsun Assoc. Prof. Dr. Zülkif Dağlı, accompanied by District Governor of Bafra Cevdet Ertürkmen, Mayor of Bafra Hamit Kılıç, the boards of the Bafra Chamber of Commerce and Industry, Bafra Commodity Exchange, Bafra Chamber of Agriculture, Bafra Greenhouse OSB, as well as the Deputy Provincial Director of Agriculture and Forestry of Antalya Gökhan Karaca, District Director of Agriculture and Forestry of Aksu İhsan İnal, and security personnel, visited our Bereket Fide production facility.</p><p>During the visit, information was exchanged on our cultivation activities and export efforts, and consultations were held on the current state of the sector.</p><p>We sincerely thank all distinguished guests for their kind visit.</p>\"}','Governor of Samsun Assoc. Prof. Dr. Zülkif Dağlı and the Bafra delegation visited Bereket Fide and consulted on sector developments.',NULL,'Samsun Governor Visit | Bereket Fide','Visit of Samsun Governor Zülkif Dağlı and the Bafra delegation to Bereket Fide production facility and sectoral assessment.','samsun, governorship, bafra, visit, bereket fide, export, greenhouse osb','2026-04-13 23:18:21.583','2026-04-13 23:18:21.583');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020021-6021-4021-a021-nnnnnnnn0021','nw010007-5007-4007-9007-nnnnnnnn0007','de','Eine Delegation aus Samsun besucht Bereket Fide','samsun-gouverneur-delegation-bereketfide-besuch','{\"html\": \"<p>Der Gouverneur von Samsun, Doz. Dr. Zülkif Dağlı, besuchte zusammen mit dem Bezirksgouverneur von Bafra Cevdet Ertürkmen, dem Bürgermeister von Bafra Hamit Kılıç, den Vorständen der Bafra Industrie- und Handelskammer, der Bafra Warenbörse, der Bafra Landwirtschaftskammer, der Bafra Gewächshaus-OSB sowie dem stellvertretenden Provinzdirektor für Landwirtschaft und Forsten in Antalya, Gökhan Karaca, dem Bezirksdirektor für Landwirtschaft und Forsten in Aksu, İhsan İnal, und Sicherheitspersonal unsere Produktionsanlage bei Bereket Fide.</p><p>Im Rahmen des Besuchs wurden Informationen über unsere Anbauaktivitäten und Exportbemühungen ausgetauscht sowie Beratungen zur aktuellen Lage des Sektors durchgeführt.</p><p>Wir danken allen geschätzten Gästen herzlich für ihren freundlichen Besuch.</p>\"}','Samsun-Gouverneur Doz. Dr. Zülkif Dağlı und die Bafra-Delegation besuchten Bereket Fide und berieten über Sektorentwicklungen.',NULL,'Besuch des Samsun-Gouverneurs | Bereket Fide','Besuch des Samsun-Gouverneurs Zülkif Dağlı und der Bafra-Delegation in der Bereket Fide Produktionsstätte.','Samsun, Gouverneur, Bafra, Besuch, Bereket Fide, Export, Gewächshaus-OSB','2026-04-13 23:18:21.585','2026-04-13 23:18:21.585');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020022-6022-4022-a022-nnnnnnnn0022','nw010008-5008-4008-9008-nnnnnnnn0008','tr','Aksu Protokolünden Bereket Fide\'ye Ziyaret','aksu-protokolu-bereketfide-ziyareti','{\"html\": \"<p>Aksu Kaymakamımız Sayın Ahmet Hikmet Şahin, Aksu İlçe Komutanı Jandarma Teğmen Hulusi Mehmet Müdük ve Aksu İlçe Tarım ve Orman Müdürü İhsan İnal, işletmemizi ziyaret etmiştir.</p><p>Gerçekleştirilen nazik ziyaret dolayısıyla kendilerine teşekkür ederiz.</p>\"}','Aksu Kaymakamı, İlçe Komutanı ve Tarım Müdürü, Bereket Fide işletmesini ziyaret etti.',NULL,'Aksu Protokolü Ziyareti | Bereket Fide','Aksu Kaymakamı Ahmet Hikmet Şahin ve Aksu protokolünün Bereket Fide ziyareti.','aksu, kaymakamlık, jandarma, tarım orman müdürü, ziyaret, bereket fide','2026-04-13 23:18:21.581','2026-04-13 23:18:21.581');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020023-6023-4023-a023-nnnnnnnn0023','nw010008-5008-4008-9008-nnnnnnnn0008','en','A Visit from Aksu Protocol to Bereket Fide','aksu-protocol-bereketfide-visit','{\"html\": \"<p>Aksu District Governor Ahmet Hikmet Şahin, Aksu District Commander Gendarmerie Lieutenant Hulusi Mehmet Müdük, and Aksu District Director of Agriculture and Forestry İhsan İnal visited our facility.</p><p>We sincerely thank all distinguished guests for their kind visit.</p>\"}','Aksu District Governor, District Commander and Agriculture Director visited Bereket Fide.',NULL,'Aksu Protocol Visit | Bereket Fide','Visit of Aksu District Governor Ahmet Hikmet Şahin and the Aksu protocol delegation to Bereket Fide.','aksu, district governor, gendarmerie, agriculture director, visit, bereket fide','2026-04-13 23:18:21.583','2026-04-13 23:18:21.583');
INSERT IGNORE INTO `custom_pages_i18n` (`id`, `page_id`, `locale`, `title`, `slug`, `content`, `summary`, `featured_image_alt`, `meta_title`, `meta_description`, `tags`, `created_at`, `updated_at`) VALUES ('nw020024-6024-4024-a024-nnnnnnnn0024','nw010008-5008-4008-9008-nnnnnnnn0008','de','Besuch des Aksu-Protokolls bei Bereket Fide','aksu-protokoll-bereketfide-besuch','{\"html\": \"<p>Der Bezirksgouverneur von Aksu, Ahmet Hikmet Şahin, der Bezirkskommandant der Gendarmerie Leutnant Hulusi Mehmet Müdük und der Bezirksdirektor für Landwirtschaft und Forsten von Aksu, İhsan İnal, besuchten unseren Betrieb.</p><p>Wir danken allen geschätzten Gästen herzlich für ihren freundlichen Besuch.</p>\"}','Bezirksgouverneur, Bezirkskommandant und Landwirtschaftsdirektor von Aksu besuchten Bereket Fide.',NULL,'Besuch des Aksu-Protokolls | Bereket Fide','Besuch des Aksu-Bezirksgouverneurs Ahmet Hikmet Şahin und des Aksu-Protokolls bei Bereket Fide.','Aksu, Bezirksgouverneur, Gendarmerie, Landwirtschaftsdirektor, Besuch, Bereket Fide','2026-04-13 23:18:21.585','2026-04-13 23:18:21.585');
